"""Textual-based interactive TUI for FactoryMind AI.

Launch with: fmind tui  (or just: fmind  when already logged in)
"""

from __future__ import annotations

from typing import ClassVar, Optional

from textual import on, work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Container, Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import (
    DataTable,
    Footer,
    Header,
    Input,
    Label,
    ListItem,
    ListView,
    RichLog,
    Static,
)

from client import config as cfg
from client.api import APIClient, APIError, get_client


# ── Helpers ────────────────────────────────────────────────────────────────────

def _make_client() -> Optional[APIClient]:
    try:
        return get_client()
    except APIError:
        return None


# ── Model Select Screen ────────────────────────────────────────────────────────

class ModelSelectScreen(Screen):
    """Pick a default model from the server catalog."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    ModelSelectScreen {
        align: center middle;
    }
    #model-table {
        width: 80;
        height: auto;
        border: solid $primary;
    }
    #model-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="model-table", cursor_type="row")
            yield Static("Enter to select · Esc to go back", id="model-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("Model", "Description", "Cached", "Loaded")
        self._load_models()

    @work(thread=True)
    def _load_models(self) -> None:
        try:
            models = self._api.list_models()
        except APIError:
            models = []
        self.call_from_thread(self._populate_table, models)

    def _populate_table(self, models: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for m in models:
            table.add_row(
                m["id"],
                m.get("description", ""),
                "✓" if m.get("cached") else "–",
                "● loaded" if m.get("loaded") else "○",
                key=m["id"],
            )

    @on(DataTable.RowSelected)
    def row_selected(self, event: DataTable.RowSelected) -> None:
        model_id = str(event.row_key.value)
        cfg.save_default_model(model_id)
        self.app.pop_screen()
        self.app.notify(f"Default model set to {model_id}", title="Model selected")


# ── Chat Screen ────────────────────────────────────────────────────────────────

class ChatScreen(Screen):
    """Full interactive chat with streaming responses."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("ctrl+c", "app.pop_screen", "Back", show=False),
        Binding("escape", "app.pop_screen", "Back"),
        Binding("ctrl+l", "clear_history", "Clear"),
    ]

    CSS = """
    ChatScreen {
        layout: vertical;
    }
    #messages {
        height: 1fr;
        border: solid $primary;
        overflow-y: auto;
        padding: 0 1;
    }
    #input-row {
        height: 3;
        layout: horizontal;
    }
    #chat-input {
        width: 1fr;
    }
    #model-label {
        color: $success;
        padding: 0 1;
        content-align: center middle;
        height: 3;
    }
    """

    def __init__(self, api: APIClient, model: str) -> None:
        super().__init__()
        self._api = api
        self._model = model
        self._history: list[dict] = []
        self._chat_id: Optional[str] = None

    def compose(self) -> ComposeResult:
        yield Header(show_clock=True)
        yield RichLog(id="messages", highlight=True, markup=True, wrap=True)
        with Horizontal(id="input-row"):
            yield Label(f"[{self._model}]", id="model-label")
            yield Input(placeholder="Type a message… (Esc = back)", id="chat-input")
        yield Footer()

    def on_mount(self) -> None:
        log = self.query_one(RichLog)
        log.write(
            f"[dim]Chat started with [bold]{self._model}[/bold]. "
            "Type a message and press Enter.[/dim]\n"
        )
        self.query_one(Input).focus()

    @on(Input.Submitted)
    def on_input_submitted(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return
        event.input.clear()

        log = self.query_one(RichLog)
        log.write(f"\n[bold blue]You:[/bold blue] {text}\n")

        self._history.append({"role": "user", "content": text})
        self._stream_response(list(self._history))

    def action_clear_history(self) -> None:
        self._history.clear()
        self._chat_id = None
        self.query_one(RichLog).clear()
        self.query_one(RichLog).write("[dim]History cleared.[/dim]\n")

    @work(exclusive=False)
    async def _stream_response(self, messages: list[dict]) -> None:
        log = self.query_one(RichLog)
        log.write(f"\n[bold green][{self._model}][/bold green] ")

        full_text = ""
        try:
            async for chunk in self._api.async_chat_stream(
                model=self._model,
                messages=messages,
                chat_id=self._chat_id,
            ):
                log.write(chunk, expand=False)
                full_text += chunk
        except APIError as exc:
            log.write(f"\n[red]Error:[/red] {exc}\n")
            self._history.pop()  # remove user message that failed
            return
        except Exception as exc:
            log.write(f"\n[red]Unexpected error:[/red] {exc}\n")
            self._history.pop()
            return

        log.write("\n")
        if full_text:
            self._history.append({"role": "assistant", "content": full_text})


