import ast, pathlib, sys
errors = []
for p in pathlib.Path('.').rglob('*.py'):
    if any(x in str(p) for x in ['.venv', '.claude', '__pycache__']):
        continue
    try:
        ast.parse(p.read_text())
    except SyntaxError as e:
        errors.append(f'{p}: {e}')
if errors:
    for e in errors: print(e)
    sys.exit(1)
else:
    print(f'Syntax OK – {sum(1 for _ in pathlib.Path(\".\").rglob(\"*.py\"))} files checked')
"
